361→int parity_compare(const game_state_snapshot *a, const game_state_snapshot *b,
362→                   const char *fn_name, int frame, int objnum)
363→{
364→	int divergences = 0;
365→
366→	if (!parity_initialized)
367→		parity_init();
368→
369→	/* Compare objects up to the higher of the two highest indices */
370→	int max_obj = a->highest_object_index;
371→	if (b->highest_object_index > max_obj)
372→		max_obj = b->highest_object_index;
373→
374→	if (a->highest_object_index != b->highest_object_index) {
375→		parity_log("PARITY DIVERGE frame=%d fn=%s obj=%d\n", frame, fn_name, objnum);
376→		parity_log("  Highest_object_index: OCaml=%d C=%d\n",
377→			a->highest_object_index, b->highest_object_index);
378→		divergences++;
379→	}
380→
381→	int obj_divergences = 0;
382→	for (int i = 0; i <= max_obj && i < PARITY_MAX_OBJECTS; i++) {
383→		int d = compare_object(&a->objects[i], &b->objects[i], i, fn_name, frame);
384→		if (d > 0 && obj_divergences == 0) {
385→			/* Print header on first object divergence */
386→			if (divergences == 0)
387→				parity_log("PARITY DIVERGE frame=%d fn=%s obj=%d\n", frame, fn_name, objnum);
388→		}
389→		obj_divergences += d;
390→
391→		/* Compare AI local for robots */
392→		if (a->objects[i].control_type == 2 || b->objects[i].control_type == 2) { /* CT_AI */
393→			int ad = compare_ai_local(&a->ai_local_info[i], &b->ai_local_info[i], i);
394→			if (ad > 0 && obj_divergences == 0 && divergences == 0)
395→				parity_log("PARITY DIVERGE frame=%d fn=%s obj=%d\n", frame, fn_name, objnum);
396→			obj_divergences += ad;
397→		}
398→	}
399→	divergences += obj_divergences;
400→
401→	/* Compare players */
402→	for (int i = 0; i < PARITY_MAX_PLAYERS; i++) {
403→		int d = compare_player(&a->players[i], &b->players[i], i);
404→		if (d > 0 && divergences == 0)
405→			parity_log("PARITY DIVERGE frame=%d fn=%s obj=%d\n", frame, fn_name, objnum);
406→		divergences += d;
407→	}
408→
409→	/* Compare walls */
410→	int max_walls = a->num_walls;
411→	if (b->num_walls > max_walls)
412→		max_walls = b->num_walls;
413→	for (int i = 0; i < max_walls && i < PARITY_MAX_WALLS; i++) {
414→		int d = compare_wall(&a->walls[i], &b->walls[i], i);
415→		if (d > 0 && divergences == 0)
416→			parity_log("PARITY DIVERGE frame=%d fn=%s obj=%d\n", frame, fn_name, objnum);
417→		divergences += d;
418→	}
419→
420→	/* Compare globals */
421→	if (a->player_is_dead != b->player_is_dead) {
422→		if (divergences == 0)
423→			parity_log("PARITY DIVERGE frame=%d fn=%s obj=%d\n", frame, fn_name, objnum);
424→		parity_log("  Player_is_dead: OCaml=%d C=%d\n", a->player_is_dead, b->player_is_dead);
425→		divergences++;
426→	}
427→	if (a->player_exploded != b->player_exploded) {
428→		if (divergences == 0)
429→			parity_log("PARITY DIVERGE frame=%d fn=%s obj=%d\n", frame, fn_name, objnum);
430→		parity_log("  Player_exploded: OCaml=%d C=%d\n", a->player_exploded, b->player_exploded);
431→		divergences++;
432→	}
433→	if (a->overall_agitation != b->overall_agitation) {
434→		if (divergences == 0)
435→			parity_log("PARITY DIVERGE frame=%d fn=%s obj=%d\n", frame, fn_name, objnum);
436→		parity_log("  Overall_agitation: OCaml=%d C=%d\n", a->overall_agitation, b->overall_agitation);
437→		divergences++;
438→	}
439→
440→	/* Note: we do NOT compare rand_state here. RNG divergence is expected
441→	 * when OCaml calls P_Rand differently. Instead, we restore RNG state
442→	 * before each C run. */
443→
444→	if (divergences > 0) {
445→		parity_total_divergences += divergences;
446→		parity_log("  [total %d divergent fields in this call, %d cumulative]\n",
447→			divergences, parity_total_divergences);
448→
449→		if (parity_assert_on_diverge) {
450→			fprintf(stderr, "PARITY ASSERT: crashing due to OX_PARITY_ASSERT=1\n");
451→			abort();
452→		}
453→	}
454→
455→	return divergences;
456→}
