711→  (* Helper: compute visibility *)
712→  let compute_vis () =
713→    if !visibility_and_vec_computed = 0
714→    then (
715→      let vpx, vpy, vpz = !vis_vec_pos in
716→      let pv, vtx, vty, vtz, _snd =
