718→      in
719→      player_visibility := pv;
720→      vec_to_player := vtx, vty, vtz;
721→      (* Mirror compute_vis_and_vec_v2 side effects on local refs.
722→         The effect updates C structs directly, but OCaml's pack_result
723→         would overwrite those with stale local values if we don't
724→         replicate the updates here. *)
725→      (* C lines 2177-2181: wake up resting robots on first clear sight *)
726→      if pv = 2 && !previous_visibility <> 2
727→      then
728→        if !goal_state = ais_rest || !current_state = ais_rest
729→        then (
730→          goal_state := ais_fire;
731→          current_state := ais_fire);
732→      previous_visibility := pv;
733→      if pv <> 0 then time_player_seen := game_time;
734→      visibility_and_vec_computed := 1)
735→  in
736→  (* Helper: unpack path state returned by path effects.
737→     Array: [0]hide_index [1]path_length [2]cur_path_index [3]path_dir
738→            [4]mode [5]goal_segment [6]time_player_seen [7]player_awareness_type
739→            [8]behavior [9]hide_segment [10]skip_ai_count *)
740→  let unpack_path_state ps =
741→    hide_index := ps.(0);
742→    path_length := ps.(1);
743→    cur_path_index := ps.(2);
744→    (* ps.(3) = path_dir: not tracked as ref in D1, ignored *)
745→    mode := ps.(4);
746→    goal_segment := ps.(5);
747→    time_player_seen := ps.(6);
748→    player_awareness_type := ps.(7);
749→    behavior := ps.(8);
750→    hide_segment := ps.(9);
751→    skip_ai_count := ps.(10)
752→  in
753→  (* Helper: pack result *)
754→  let pack_result () =
755→    let r = Array.create ~len:ai_state_size 0 in
756→    r.(idx_skip_ai_count) <- !skip_ai_count;
757→    r.(idx_goal_state) <- !goal_state;
758→    r.(idx_current_state) <- !current_state;
759→    r.(idx_cloaked) <- !cloaked;
760→    r.(idx_current_gun) <- !current_gun;
761→    r.(idx_cur_path_index) <- !cur_path_index;
762→    r.(idx_behavior) <- !behavior;
763→    r.(idx_hide_index) <- !hide_index;
764→    r.(idx_path_length) <- !path_length;
765→    r.(idx_sub_flags) <- _sub_flags;
766→    r.(idx_goalside) <- !goalside;
767→    r.(idx_hide_segment) <- !hide_segment;
768→    r.(idx_next_fire) <- !next_fire;
